CREATE ALGORITHM=UNDEFINED DEFINER=`lynxlocal`@`%` SQL SECURITY DEFINER VIEW `viewitensprojetoemaberto` AS select `osi`.`IdOrdemServico` AS `IDOrdemServico`,`osi`.`IdOrdemServicoItem` AS `IdOrdemServicoItem`,`osi`.`idProjeto` AS `IdProjeto`,`osi`.`Projeto` AS `Projeto`,`osi`.`IdTag` AS `IdTag`,`osi`.`Tag` AS `Tag`,`osi`.`CodMatFabricante` AS `CodMatFabricante`,round(`osi2`.`RomaneioTotalEnviado`,2) AS `RomaneioTotalEnviado`,round(`osi`.`RomaneioSaldoEnviar`,2) AS `RomaneioSaldoEnviar`,round(`osi`.`QtdeTotal`,2) AS `QtdeTotal`,round(`osi`.`AreaPintura`,2) AS `AreaPintura`,round((`osi`.`AreaPinturaUnitario` / `osi`.`qtde`),2) AS `AreaPinturaUnitario`,round(`osi`.`Peso`,2) AS `Peso`,round((`osi`.`PesoUnitario` / `osi`.`qtde`),2) AS `PesoUnitario`,`osi`.`Acabamento` AS `Acabamento`,`osi`.`OrdemServicoItemFinalizado` AS `OrdemServicoItemFinalizado`,round(`osi2`.`Comprimentocaixadelimitadora`,2) AS `Comprimentocaixadelimitadora`,round(`osi2`.`Larguracaixadelimitadora`,2) AS `Larguracaixadelimitadora`,round(`osi2`.`Espessuracaixadelimitadora`,2) AS `Espessuracaixadelimitadora`,`osi2`.`DescResumo` AS `DescResumo`,`osi`.`DescDetal` AS `DescDetal`,`osi`.`Unidade` AS `Unidade`,`osi`.`txtPintura` AS `TxtPintura`,`osi`.`Liberado_Engenharia` AS `Liberado_Engenharia`,`osi2`.`ProdutoPrincipal` AS `ProdutoPrincipal`,`osi2`.`EnderecoArquivo` AS `EnderecoArquivo`,`osi2`.`EnviadoParaRomaneio` AS `EnviadoParaRomaneio`,`osi`.`EnderecoArquivoItemOrdemServico` AS `EnderecoArquivoItemOrdemServico` from (((`ordemservicoitem` `osi` join `projetos` `p` on((`p`.`IdProjeto` = `osi`.`idProjeto`))) join `tags` `t` on((`t`.`IdTag` = `osi`.`IdTag`))) left join `ordemservicoitem` `osi2` on((`osi2`.`IdOrdemServicoItem` = `osi`.`IdOrdemServicoItem`))) where ((coalesce(`p`.`Finalizado`,'') = '') and (coalesce(`t`.`Finalizado`,'') = '') and (coalesce(trim(`osi`.`D_E_L_E_T_E`),'') = '')) order by `osi`.`IdOrdemServicoItem`,`osi`.`IdOrdemServico`